+      cache.set('key3', 'value3');
+
+      // Access key1 to make it most recently used
+      cache.get('key1');
+
+      // Fill remaining capacity
+      for (let i = 4; i <= 10; i++) {
+        cache.set(`key${i}`, `value${i}`);
+      }
+
+      // Add one more, should evict key2 (now least recently used)
+      cache.set('key11', 'value11');
